function LxAtlasAsset:AddRequestCb(spriteName, path, cb, obj)
    table.insert(self._requestCbs, {name=spriteName, path = path, cb=cb, obj = obj})
end

function LxAtlasAsset:ExecuteCb()
    self._lastReleaseTime = Time.realtimeSinceStartup

    local cbList = self._requestCbs
    local atlasCbList = self._reqAtlasCbs
    self._requestCbs = {}
    self._reqAtlasCbs = {}
    for k,v in ipairs(cbList) do
        local name = v.name
        local cb = v.cb
        local obj = v.obj
        local path = v.path
        v.cb = nil
        v.obj = nil
        v.path = nil
        self:RequestSprite(name, path, cb, obj)
    end

    for k,v in ipairs(atlasCbList) do
        local cb = v.cb
        local obj = v.obj
        v.cb = nil
        v.obj = nil
        cb(obj, self)
    end
end

function LxAtlasAsset:AddRef()
    self._refCount = self._refCount + 1
end

function LxAtlasAsset:Release()
    self._refCount = self._refCount - 1
    if self._refCount < 0 then
        self._refCount = 0
    end
    self._lastReleaseTime = Time.realtimeSinceStartup
end

function LxAtlasAsset:RequestSprite(spriteName, path, cb, obj)
    if not self._recordSprites[spriteName] then
        self._recordSprites[spriteName] = true
        if self._spriteAtlasAsset then
            local sprite = nil
            if self._isSimulateMode then
                --模拟资源模式，从编辑器直接读取sprite，
                --可以设置sprite atlas 打包的时候才packview， 降低开发时候等待spriteatals pack view事件
                local spritePath = LxResPathUtil.GetSpritePath(spriteName)
                if not string.isempty(spritePath) then
                    sprite = PJXUtil.EditorLoadAsset("Assets/Res/"..spritePath..".png", typeofSprite)
                end
            else
                sprite = self._spriteAtlasAsset:GetSprite(spriteName)
            end
            if sprite ~= nil then
                sprite.name = spriteName
                self._sprites[spriteName] = sprite
            end
        end
    end
    local sprite = self._sprites[spriteName]
    if sprite then
        self:AddRef()
    end
    if not cb(obj, sprite, path) then
        self:ReleaseSprite(spriteName)
    end
end

function LxAtlasAsset:ReleaseSprite(spriteName)
    local sprite = self._sprites[spriteName]
    if sprite then
        self:Release()
    end
end

function LxAtlasAsset:IsCanDispose()
    if self._loading then
        return false
    end
    return self._refCount <= 0
end

function LxAtlasAsset:IsReachFreeTime(curTime)
    if curTime - self._lastReleaseTime >= self._deadlineTime then
        return true
    end
    return false
end

